SELECT quality_score
FROM data_quality_reports
WHERE quality_score > 0.8;

SELECT AVG(importance) AS avg_importance
FROM model_features
WHERE model_id = 1;

SELECT model_id, AVG(importance) AS average_importance
FROM model_features
GROUP BY model_id;

SELECT AVG(performance_metrics) AS avg_performance
FROM model_monitoring
WHERE model_id = 0;

SELECT response_category
FROM responses
WHERE spkitemid = '1';

SELECT version_description
FROM dataset_versions
WHERE dataset_id = 1;

SELECT AVG(importance) AS average_feature_importance
FROM model_features
WHERE model_id = 1;

SELECT project_name
FROM collaborations
WHERE collaboration_id = 0;
